if (!global.get('initialized')) {
    global.set('initialized', true);

    global.set('q_load_out',   []);
    global.set('q_pallet_out', []);
    global.set('q_robot_out',  []);
    global.set('q_camera_out', []);
    global.set('q_watch_out',  []);

    global.set('status_load',       'idle');
    global.set('status_loadpallet', 'idle');
    global.set('status_robot',      'idle');
    global.set('status_camera',     'idle');
    global.set('status_watch',      'idle');
    global.set('status_label',      'idle');

    global.set('lock_load',       false);
    global.set('lock_loadpallet', false);
    global.set('lock_robot',      false);
    global.set('lock_camera',     false);
    global.set('lock_watch',      false);
    global.set('lock_label',      false);

    global.set('ts_blocked_load',    null);
    global.set('ts_blocked_robot',   null);
    global.set('ts_starving_robot',  null);

    global.set('package_counter', 0);
    global.set('pallet_counter',  0);
    global.set('n_scrap',  0);
    global.set('n_good',   0);
    global.set('ready_pallets',  10);
    global.set('loaded_pallets', 0);

    global.set('energy_load_kwh',   0);
    global.set('energy_pallet_kwh', 0);
    global.set('energy_robot_kwh',  0);

    global.set('config', {
        load_speed:          5,
        pallet_speed:        10,
        robot_speed:         4,
        max_queue_size:      20,
        ready_packages:      500,
        pulsar_url:          'http://broker:9553'
    });

    node.warn('✅ Global state initialized (v6)');
}
return msg;

const cfg       = global.get('config') || {};
const threshold = cfg.max_queue_size 

const qLoad   = (global.get('q_load_out')   || []).length;
const qPallet = (global.get('q_pallet_out') || []).length;
const qRobot  = (global.get('q_robot_out')  || []).length;
const qCamera = (global.get('q_camera_out') || []).length;
const qWatch  = (global.get('q_watch_out')  || []).length;

const events = [];

if (global.get('lock_load') && qLoad < threshold) {
    global.set('lock_load', false);
    global.set('ts_blocked_load', null);
    events.push({ machine: 'LoadPackage', reason: 'q_load_out=' + qLoad });
}
if (global.get('lock_loadpallet') && qPallet < threshold) {
    global.set('lock_loadpallet', false);
    events.push({ machine: 'LoadPallets', reason: 'q_pallet_out=' + qPallet });
}
if (global.get('lock_robot') && qRobot < threshold) {
    global.set('lock_robot', false);
    global.set('ts_blocked_robot', null);
    events.push({ machine: 'Robot', reason: 'q_robot_out=' + qRobot });
}


if (events.length > 0) {
    //node.warn('🔓 ' + JSON.stringify(events));
    msg.payload = { type: 'auto_unlock', events, ts: new Date().toISOString() };
    return msg;
}
return null;

// Reads load_speed from global config on every cycle.
// Triggers load_package_fn immediately, then reschedules itself.
// Changing load_speed via REST takes effect on the next setTimeout fire.
const cfg        = global.get('config') || {};
const loadSpeed  = Math.max(0.1, cfg.load_speed || 5);  // pkg/min, floor at 0.1
const intervalMs = Math.round(60000 / loadSpeed);

await new Promise(r => setTimeout(r, intervalMs));

// Trigger load logic immediately this cycle
node.send([{ payload: Date.now() }, null]);

// Status output so we can see the active interval
node.send([null, { payload: {
    machine:     'LoadTimer',
    load_speed:  loadSpeed,
    interval_ms: intervalMs,
    ts:          new Date().toISOString()
}}]);
return null;

const cfg          = global.get('config') || {};
const maxQ         = cfg.max_queue_size || 20;
const loadSpeed    = Math.max(0.1, cfg.load_speed || 5);
let   ready_packages = cfg.ready_packages !== undefined ? cfg.ready_packages : 500;
let   pkgCounter   = global.get('package_counter') || 0;
const processingMs = Math.round(60000 / loadSpeed);

// ── Energetic consumption (exponential: 1 KWh @ speed=1, 3 KWh @ speed=20) ──
const LOAD_E_MIN = 1.0, LOAD_E_MAX = 3.0, LOAD_SPEED_MAX = 20;
const loadPowerKw  = LOAD_E_MIN * Math.pow(LOAD_E_MAX / LOAD_E_MIN, (loadSpeed - 1) / (LOAD_SPEED_MAX - 1));
const loadEnergyKwh = loadPowerKw * (processingMs / 3600000);   // kW × h
let   totalEnergyLoad = (global.get('energy_load_kwh') || 0) + loadEnergyKwh;
global.set('energy_load_kwh', totalEnergyLoad);

if (global.get('lock_load')) {
    if (!global.get('ts_blocked_load')) global.set('ts_blocked_load', Date.now());
    const blockedMs = Date.now() - global.get('ts_blocked_load');
    const qLen = (global.get('q_load_out') || []).length;
    global.set('status_load', 'blocked');
    const eventMsg = {
        payload: null,
        topic: 'load-package',
        eventLog: {
            case_id: "---",
            activity: 'Load Package',
            machine: 'LoadPackage',
            duration_ms: processingMs,
            attributes: {
                remaining_packages: ready_packages,
                charger_speed: loadSpeed,
                machine_status: 'blocked',
                power_kw: Math.round(loadPowerKw * 1000) / 1000,
                energy_kwh: Math.round(loadEnergyKwh * 1e6) / 1e6,
                total_energy_load_kwh: Math.round(totalEnergyLoad * 1000) / 1000,
            }
        }
    };
    node.send([eventMsg, { payload: { machine: 'LoadPackage', charger_speed: loadSpeed, status: 'blocked', duration_ms: blockedMs, producing_status: 'blocked', q_load_out_size: qLen, ts: new Date().toISOString() }}]);
    return null;
}

const qCheck = (global.get('q_load_out') || []).length;
if (qCheck >= maxQ) {
    global.set('lock_load', true);
    global.set('ts_blocked_load', Date.now());
    global.set('status_load', 'blocked');
    const eventMsg = {
        payload: null,
        topic: 'load-package',
        eventLog: {
            case_id: "---",
            activity: 'Load Package',
            machine: 'LoadPackage',
            duration_ms: processingMs,
            attributes: {
                remaining_packages: ready_packages,
                charger_speed: loadSpeed,
                machine_status: 'blocked',
                power_kw: Math.round(loadPowerKw * 1000) / 1000,
                energy_kwh: Math.round(loadEnergyKwh * 1e6) / 1e6,
                total_energy_load_kwh: Math.round(totalEnergyLoad * 1000) / 1000,
            }
        }
    };
    node.send([eventMsg, { payload: { machine: 'LoadPackage', charger_speed: loadSpeed, status: 'blocked', duration_ms: 0, producing_status: 'blocked', q_load_out_size: qCheck, ts: new Date().toISOString() }}]);
    return null;
}

global.set('ts_blocked_load', null);
pkgCounter++;
ready_packages--;

const tsStart = new Date().toISOString();
const tsEnd   = new Date(Date.now() + processingMs).toISOString();

const pkg = {
    package_id:     'PKG-' + String(pkgCounter).padStart(5, '0'),
    ts_created:     tsStart,
    ts_load_done:   tsEnd,
    charger_speed:  loadSpeed,
    machine_status: 'producing',
    load_power_kw:  Math.round(loadPowerKw * 1000) / 1000,
    load_energy_kwh: Math.round(loadEnergyKwh * 1e6) / 1e6
};

const q = global.get('q_load_out') || [];
q.push(pkg);
global.set('q_load_out',      q);
global.set('package_counter', pkgCounter);
cfg.ready_packages = ready_packages;
global.set('config', cfg);
global.set('status_load', 'producing');

const eventMsg = {
    payload: pkg,
    topic:   'load-package',
    eventLog: {
        case_id:     pkg.package_id,
        activity:    'Load Package',
        machine:     'LoadPackage',
        ts_start:    tsStart,
        ts_end:      tsEnd,
        duration_ms: processingMs,
        attributes: {
            remaining_packages: ready_packages,
            charger_speed:    loadSpeed,
            machine_status:   'producing',
            power_kw:         Math.round(loadPowerKw * 1000) / 1000,
            energy_kwh:       Math.round(loadEnergyKwh * 1e6) / 1e6,
            total_energy_load_kwh: Math.round(totalEnergyLoad * 1000) / 1000,
            consumption_note: 'energy for this cycle at speed ' + loadSpeed
        }
    }
};

const statusMsg = { payload: {
    machine: 'LoadPackage', status: 'producing',
    charger_speed: loadSpeed, ready_packages,
    processing_ms: processingMs,
    q_load_out_size: q.length, ts: tsStart
}};

node.send([eventMsg, statusMsg]);
node.status({fill:"blue",shape:"dot",text: q.length});
return null;

// Reads robot_speed from global config on every cycle.
// Triggers robot_fn immediately, then reschedules itself.
// Changing robot_speed via REST takes effect on the next setTimeout fire.
const cfg        = global.get('config') || {};
const robotSpeed = Math.max(0.1, cfg.robot_speed || 4);  // pcs/min, floor at 0.1
const intervalMs = Math.round(60000 / robotSpeed);


await new Promise(r => setTimeout(r, intervalMs));


// Trigger robot logic immediately this cycle
node.send([{ payload: Date.now() }, null]);

// Status output
node.send([null, { payload: {
    machine:     'RobotTimer',
    robot_speed: robotSpeed,
    interval_ms: intervalMs,
    ts:          new Date().toISOString()
}}]);
return null;

const cfg          = global.get('config') || {};
const maxQ         = cfg.max_queue_size || 20;
const robotSpeed   = Math.max(0.1, cfg.robot_speed || 4);
let   qIn      = global.get('q_load_out')   || [];
let   qPallet  = global.get('q_pallet_out') || [];
let   qOut     = global.get('q_robot_out')  || [];
let   loadedPallets = global.get('loaded_pallets') || 0;
const processingMs  = Math.round(60000 / robotSpeed);

// ── Energetic consumption (exponential: 1 KWh @ speed=1, 10 KWh @ speed=20) ──
const ROBOT_E_MIN = 1.0, ROBOT_E_MAX = 10.0, ROBOT_SPEED_MAX = 20;
const robotPowerKw   = ROBOT_E_MIN * Math.pow(ROBOT_E_MAX / ROBOT_E_MIN, (robotSpeed - 1) / (ROBOT_SPEED_MAX - 1));
const robotEnergyKwh = robotPowerKw * (processingMs / 3600000);   // kW × h
let   totalEnergyRobot = (global.get('energy_robot_kwh') || 0) + robotEnergyKwh;
global.set('energy_robot_kwh', totalEnergyRobot);

if (global.get('lock_robot')) {
    if (!global.get('ts_blocked_robot')) global.set('ts_blocked_robot', Date.now());
    const blockedMs = Date.now() - global.get('ts_blocked_robot');
    global.set('status_robot', 'blocked');
    const eventMsg = {
        payload: null,
        topic:   'robot',
        eventLog: {
            case_id:     "---",
            activity:    'Robot Processing',
            machine:     'Robot',
            duration_ms: processingMs,
            attributes: {
                robot_speed:           robotSpeed,
                machine_status:        "blocked",
                ready_pallets:         qPallet.length,
                ready_packages:        qIn.length,
                prepared_packages:     qOut.length,
                power_kw:              Math.round(robotPowerKw * 1000) / 1000,
                energy_kwh:            Math.round(robotEnergyKwh * 1e6) / 1e6,
                total_energy_robot_kwh: Math.round(totalEnergyRobot * 1000) / 1000,
                consumption_note:      'energy for this cycle at speed ' + robotSpeed
            }
        }
    };
    node.send([eventMsg, { payload: { machine: 'Robot', robot_speed: robotSpeed, status: 'blocked', producing_status: 'blocked', duration_ms: blockedMs, q_in: qIn.length, q_pallet: qPallet.length, q_out: qOut.length, ts: new Date().toISOString() }}]);
    return null;
}
if (qOut.length >= maxQ) {
    global.set('lock_robot', true);
    global.set('ts_blocked_robot', Date.now());
    global.set('status_robot', 'blocked');
    const eventMsg = {
        payload: null,
        topic:   'robot',
        eventLog: {
            case_id:     "---",
            activity:    'Robot Processing',
            machine:     'Robot',
            duration_ms: processingMs,
            attributes: {
                robot_speed:           robotSpeed,
                machine_status:        "blocked",
                ready_pallets:         qPallet.length,
                ready_packages:        qIn.length,
                prepared_packages:     qOut.length,
                power_kw:              Math.round(robotPowerKw * 1000) / 1000,
                energy_kwh:            Math.round(robotEnergyKwh * 1e6) / 1e6,
                total_energy_robot_kwh: Math.round(totalEnergyRobot * 1000) / 1000,
                consumption_note:      'energy for this cycle at speed ' + robotSpeed
            }
        }
    };
    node.send([eventMsg, { payload: { machine: 'Robot', robot_speed: robotSpeed, status: 'blocked', producing_status: 'blocked', duration_ms: 0, q_out: qOut.length, ts: new Date().toISOString() }}]);
    return null;
}

if (qIn.length === 0 || qPallet.length === 0) {
    if (!global.get('ts_starving_robot')) global.set('ts_starving_robot', Date.now());
    const starvingMs = Date.now() - global.get('ts_starving_robot');
    const reason = qIn.length === 0 && qPallet.length === 0 ? 'no_packages_no_pallets'
                 : qIn.length === 0 ? 'no_packages' : 'no_pallets';
    global.set('status_robot', 'starving');
    const eventMsg = {
        payload: null,
        topic:   'robot',
        eventLog: {
            case_id:     "---",
            activity:    'Robot Processing',
            machine:     'Robot',
            duration_ms: processingMs,
            attributes: {
                robot_speed:           robotSpeed,
                machine_status:        "starving",
                ready_pallets:         qPallet.length,
                ready_packages:        qIn.length,
                prepared_packages:     qOut.length,
                power_kw:              Math.round(robotPowerKw * 1000) / 1000,
                energy_kwh:            Math.round(robotEnergyKwh * 1e6) / 1e6,
                total_energy_robot_kwh: Math.round(totalEnergyRobot * 1000) / 1000,
                consumption_note:      'energy for this cycle at speed ' + robotSpeed
            }
        }
    };
    node.send([eventMsg, { payload: { machine: 'Robot', status: 'starving',  robot_speed: robotSpeed, producing_status: 'starving', duration_ms: starvingMs, reason, q_out: qOut.length, q_in: qIn.length, q_pallet: qPallet.length, ts: new Date().toISOString() }}]);
    return null;
}

global.set('ts_blocked_robot',  null);
global.set('ts_starving_robot', null);

const pkg    = qIn.shift();
const pallet = qPallet.shift();
loadedPallets++;
global.set('q_load_out',    qIn);
global.set('q_pallet_out',  qPallet);
global.set('loaded_pallets', loadedPallets);

const minQ = 0.90, maxQuality = 0.99, midSpeed = 10, steepness = 0.3;
const quality = minQ + (maxQuality - minQ) / (1 + Math.exp(steepness * (robotSpeed - midSpeed)));

const tsStart = new Date().toISOString();
const tsEnd   = new Date(Date.now() + processingMs).toISOString();

pkg.ts_robot_start    = tsStart;
pkg.ts_robot_done     = tsEnd;
pkg.robot_quality_pct = Math.round(quality * 10000) / 100;
pkg.robot_speed       = robotSpeed;
pkg.pallet_id         = pallet.pallet_id;
pkg.robot_power_kw    = Math.round(robotPowerKw * 1000) / 1000;
pkg.robot_energy_kwh  = Math.round(robotEnergyKwh * 1e6) / 1e6;

qOut.push(pkg);
global.set('q_robot_out', qOut);
global.set('status_robot', 'producing');

const eventMsg = {
    payload: pkg,
    topic:   'robot',
    eventLog: {
        case_id:     pkg.package_id,
        activity:    'Robot Processing',
        machine:     'Robot',
        ts_start:    tsStart,
        ts_end:      tsEnd,
        duration_ms: processingMs,
        attributes: {
            robot_speed:           robotSpeed,
            machine_status:        "producing",
            produced_quality_pct:  pkg.robot_quality_pct,
            pallet_id:             pallet.pallet_id,
            ready_pallets:         qPallet.length,
            ready_packages:        qIn.length,
            prepared_packages:     qOut.length,
            power_kw:              Math.round(robotPowerKw * 1000) / 1000,
            energy_kwh:            Math.round(robotEnergyKwh * 1e6) / 1e6,
            total_energy_robot_kwh: Math.round(totalEnergyRobot * 1000) / 1000,
            consumption_note:      'energy for this cycle at speed ' + robotSpeed
        }
    }
};

const statusMsg = { payload: {
    machine: 'Robot', status: 'producing',
    robot_speed: robotSpeed,
    processing_ms: processingMs,
    produced_quality_pct: pkg.robot_quality_pct,
    loaded_pallets: loadedPallets,
    q_in: qIn.length, q_pallet: qPallet.length, q_out: qOut.length,
    ts: tsStart
}};

node.status({fill:"green",shape:"dot",text: (qIn.length+1) + '/' + (qPallet.length+1) + '->' + qOut.length});
node.send([eventMsg, statusMsg]);
return null;

const cfg    = global.get('config') || {};
const maxQ   = cfg.max_queue_size || 20;
const fixedMs = 1000;  // Camera fixed at 1 piece per 20s
let   qIn    = global.get('q_robot_out')  || [];
let   qOut   = global.get('q_camera_out') || [];
let   nScrap = global.get('n_scrap') || 0;

if (global.get('lock_camera')) {
    global.set('status_camera', 'blocked');
    node.send([null, null, { payload: { machine: 'Camera', status: 'blocked', ts: new Date().toISOString() }}]);
    return null;
}
if (qOut.length >= maxQ) {
    global.set('lock_camera', true);
    global.set('status_camera', 'blocked');
    node.send([null, null, { payload: { machine: 'Camera', status: 'blocked', q_out: qOut.length, ts: new Date().toISOString() }}]);
    return null;
}
if (qIn.length === 0) {
    global.set('status_camera', 'starving');
    node.send([null, null, { payload: { machine: 'Camera', status: 'starving', reason: 'q_robot_out empty', ts: new Date().toISOString() }}]);
    return null;
}

const pkg = qIn.shift();
global.set('q_robot_out', qIn);
global.set('status_camera', 'producing');

//const tsStart = new Date().toISOString();
//const tsEnd   = new Date(Date.now() + fixedMs).toISOString();
const delay_ms = 1000;
const start_time = pkg.ts_robot_done;
const tsStart = new Date(Date.parse(start_time) + delay_ms).toISOString();
const tsEnd = new Date(Date.parse(start_time) + delay_ms + fixedMs).toISOString();
pkg.ts_camera_start = tsStart;
pkg.ts_camera_done  = tsEnd;

const qualityOk = Math.random() < ((pkg.robot_quality_pct || 95) / 100);
pkg.camera_quality_ok = qualityOk;

const eventMsg = {
    payload: pkg,
    topic:   'camera',
    eventLog: {
        case_id: pkg.package_id, activity: 'Camera Inspection', machine: 'Camera',
        ts_start: tsStart, ts_end: tsEnd, duration_ms: fixedMs,
        attributes: { quality_ok: qualityOk }
    }
};
const statusMsg = { payload: { machine: 'Camera', status: qualityOk ? 'producing' : 'scrapping', quality_ok: qualityOk, q_in: qIn.length, q_out: qOut.length, ts: tsStart }};

if (qualityOk) {
    qOut.push(pkg);
    global.set('q_camera_out', qOut);
    node.send([eventMsg, null, statusMsg]);
} else {
    nScrap++;
    global.set('n_scrap', nScrap);
    pkg.scrap_reason = 'camera_quality_fail';
    let lp = Math.max(0, (global.get('loaded_pallets') || 0) - 1);
    global.set('loaded_pallets', lp);
    node.send([eventMsg, { payload: pkg }, statusMsg]);
}
node.status({ fill: "blue", shape: "dot", text: qIn.length+1 + "->" + qOut.length});
return null;

const cfg    = global.get('config') || {};
const maxQ   = cfg.max_queue_size || 20;
const fixedMs = 1000;
let   qIn    = global.get('q_camera_out') || [];
let   qOut   = global.get('q_watch_out')  || [];
let   nScrap = global.get('n_scrap') || 0;

if (global.get('lock_watch')) {
    global.set('status_watch', 'blocked');
    node.send([null, null, { payload: { machine: 'Smartwatch', status: 'blocked', ts: new Date().toISOString() }}]);
    return null;
}
if (qOut.length >= maxQ) {
    global.set('lock_watch', true);
    global.set('status_watch', 'blocked');
    node.send([null, null, { payload: { machine: 'Smartwatch', status: 'blocked', q_out: qOut.length, ts: new Date().toISOString() }}]);
    return null;
}
if (qIn.length === 0) {
    global.set('status_watch', 'starving');
    node.send([null, null, { payload: { machine: 'Smartwatch', status: 'starving', reason: 'q_camera_out empty', ts: new Date().toISOString() }}]);
    return null;
}

const pkg = qIn.shift();
global.set('q_camera_out', qIn);
global.set('status_watch', 'producing');

const delay_ms = 1000;
const start_time = pkg.ts_camera_done;
const tsStart = new Date(Date.parse(start_time) + delay_ms).toISOString();
const tsEnd = new Date(Date.parse(start_time) + delay_ms + fixedMs).toISOString();
pkg.ts_watch_start = tsStart;
pkg.ts_watch_done  = tsEnd;

const qualityOk = Math.random() < ((pkg.robot_quality_pct || 95) / 100);
pkg.watch_quality_ok = qualityOk;

const eventMsg = {
    payload: pkg,
    topic:   'smartwatch',
    eventLog: {
        case_id: pkg.package_id, activity: 'Smartwatch Inspection', machine: 'Smartwatch',
        ts_start: tsStart, ts_end: tsEnd, duration_ms: fixedMs,
        attributes: { quality_ok: qualityOk }
    }
};
const statusMsg = { payload: { machine: 'Smartwatch', status: qualityOk ? 'producing' : 'scrapping', quality_ok: qualityOk, q_in: qIn.length, q_out: qOut.length, ts: tsStart }};

if (qualityOk) {
    qOut.push(pkg);
    global.set('q_watch_out', qOut);
    node.send([eventMsg, null, statusMsg]);
} else {
    nScrap++;
    global.set('n_scrap', nScrap);
    pkg.scrap_reason = 'smartwatch_quality_fail';
    let lp = Math.max(0, (global.get('loaded_pallets') || 0) - 1);
    global.set('loaded_pallets', lp);
    node.send([eventMsg, { payload: pkg }, statusMsg]);
}
node.status({fill:"blue",shape:"dot",text: qIn.length+1 + "->" + qOut.length});
return null;

const cfg    = global.get('config') || {};
const fixedMs = 1000;
let   qIn    = global.get('q_watch_out') || [];
let   nScrap = global.get('n_scrap') || 0;
let   nGood  = global.get('n_good')  || 0;

if (global.get('lock_label')) {
    global.set('status_label', 'blocked');
    node.send([null, null, null, { payload: { machine: 'Labeler', status: 'blocked', ts: new Date().toISOString() }}]);
    return null;
}
if (qIn.length === 0) {
    global.set('status_label', 'starving');
    node.send([null, null, null, { payload: { machine: 'Labeler', status: 'starving', reason: 'q_watch_out empty', ts: new Date().toISOString() }}]);
    return null;
}

global.set('status_label', 'producing');
const pkg = qIn.shift();
global.set('q_watch_out', qIn);

const delay_ms = 1000;
const start_time = pkg.ts_watch_done;
const tsStart = new Date(Date.parse(start_time) + delay_ms).toISOString();
const tsEnd = new Date(Date.parse(start_time) + delay_ms + fixedMs).toISOString();
pkg.ts_label_start = tsStart;
pkg.ts_label_done  = tsEnd;

const qualityOk = Math.random() < ((pkg.robot_quality_pct || 95) / 100);
pkg.label_quality_ok = qualityOk;

// Free pallet slot regardless of outcome
let lp = Math.max(0, (global.get('loaded_pallets') || 0) - 1);
global.set('loaded_pallets', lp);

const eventMsg = {
    payload: pkg,
    topic:   'labeler',
    eventLog: {
        case_id: pkg.package_id, activity: 'Apply & Verify Label', machine: 'Labeler',
        ts_start: tsStart, ts_end: tsEnd, duration_ms: fixedMs,
