var suggestion = "Nothing to report"
var new_robot_speed = rob_speed
var new_load_speed = pack_speed
var pass = true
var flag_increase_robot = false
var flag_decrease_robot = false
var flag_decrease_load = false
var flag_increase_load = false


// ─────────────────────────────────────────────
// ROBOT = STARVING
// ─────────────────────────────────────────────
if (rob_status === "starving") {

    // Case 1 & 2 — Package blocked (pallet queue full), Pallet producing
    // Starvation is on the pallet (product) side — not controllable.
    if (pack_status === "blocked" && pall_status === "producing") {

        if (pall_speed < rob_speed) {
            // Case 1 — Product pallet arrival too slow, cannot be commanded
            flag_decrease_robot = true;
            new_robot_speed = pall_speed;
            suggestion =
                "Robot is starving: pallet loader is slower than robot (" +
                pall_speed + " vs " + rob_speed +
                "). Put forklifts in eco mode to regulate product arrival. " +
                "Decrease speed to " + new_robot_speed + " to match current pallet throughput.";
            pass = false;

        } else {
            // Case 2 — Pallet speed sufficient, likely transient
            suggestion =
                "Robot is starving despite pallet loader speed (" + pall_speed +
                ") >= robot speed (" + rob_speed +
                "). Possible transient gap or sensor anomaly. No action taken.";
            pass = false;
        }

    // Case 3 & 4 — Pallet blocked (product queue full), Package producing
    // Starvation is on the package (pallet) side — controllable.
    } else if (pall_status === "blocked" && pack_status === "producing") {

        if (pack_speed < rob_speed) {
            // Case 3 — Package loader too slow, increase it to feed robot
            flag_increase_load = true;
            new_load_speed = rob_speed;
            suggestion =
                "Robot is starving: package loader is slower than robot (" +
                pack_speed + " vs " + rob_speed +
                "). Increase speed to " + new_load_speed + ".";
            pass = false;

        } else {
            // Case 4 — Package speed sufficient, likely transient
            suggestion =
                "Robot is starving despite package loader speed (" + pack_speed +
                ") >= robot speed (" + rob_speed +
                "). Possible transient gap or sensor anomaly. No action taken.";
            pass = false;
        }

    // Case 5 & 6 — Both producing, robot still starving
    // Robot is limited by its slowest input — speeds are not additive.
    } else if (pack_status === "producing" && pall_status === "producing") {

        const max_sustainable = Math.min(pack_speed, pall_speed);

        if (max_sustainable < rob_speed) {
            // Case 5 — Robot faster than its slowest input
            flag_decrease_robot = true;
            new_robot_speed = max_sustainable;

            if (pall_speed < pack_speed) {
                // Pallet (products) is the bottleneck — not controllable
                suggestion =
                    "Robot is starving: pallet loader speed (" + pall_speed +
                    ") is the bottleneck. Decrease speed to " + new_robot_speed + ". " +
                    "Put forklifts in eco mode to improve product flow.";
            } else {
                // Package (pallets) is the bottleneck — increase it
                flag_increase_load = true;
                new_load_speed = rob_speed;
                suggestion =
                    "Robot is starving: package loader speed (" + pack_speed +
                    ") is the bottleneck. decrease robot speed to " + new_robot_speed +
                    " and increase package loader speed to " + new_load_speed + ".";
            }
            pass = false;

        } else {
            // Case 6 — Supply sufficient, robot still starving — anomaly
            suggestion =
                "Robot is starving despite both loaders running at or above robot speed (" + rob_speed +
                "). Possible sensor fault or queue imbalance. Manual inspection recommended.";
            pass = false;
        }
    }

// ─────────────────────────────────────────────
// ROBOT = BLOCKED
// Output queue is full — root cause is downstream.
// Never speed up, only slow down.
// ─────────────────────────────────────────────
} else if (rob_status === "blocked") {

    // Case 7 — Full pipeline jam: robot blocked, both loaders backed up
    if (pack_status === "blocked" && pall_status === "blocked") {
        flag_decrease_robot = true;
        flag_decrease_load  = true;
        new_robot_speed = Math.max(0, rob_speed  - 1);
        new_load_speed  = Math.max(0, pack_speed - 1);
        suggestion =
            "Full pipeline jam: robot blocked downstream, both loader queues full. " +
            "Decrease robot speed to " + new_robot_speed +
            " and package loader speed to " + new_load_speed +
            ". Put forklifts in eco mode to slow product arrival.";
        pass = false;

    // Case 8 — Downstream blocked, package queue full, pallet still flowing
    } else if (pack_status === "blocked" && pall_status === "producing") {
        flag_decrease_robot = true;
        flag_decrease_load  = true;
        new_robot_speed = Math.max(0, rob_speed  - 1);
        new_load_speed  = Math.max(0, pack_speed - 1);
        suggestion =
            "Robot blocked downstream and package queue is full. Pallet loader still flowing. " +
            "Decrease robot speed to " + new_robot_speed +
            " and package loader speed to " + new_load_speed +
            ". Put forklifts in eco mode to prevent product queue from filling too.";
        pass = false;

    // Case 9 — Downstream blocked, pallet queue full, package still flowing
    } else if (pall_status === "blocked" && pack_status === "producing") {
        flag_decrease_robot = true;
        flag_decrease_load  = true;
        new_robot_speed = Math.max(0, rob_speed  - 1);
        new_load_speed  = Math.max(0, pack_speed - 1);
        suggestion =
            "Robot blocked downstream and pallet queue is full. Package loader still flowing. " +
            "Decrease robot speed to " + new_robot_speed +
            " and package loader speed to " + new_load_speed +
            " to prevent package queue from filling too. ";
        pass = false;

    // Case 10 — Downstream blocked, both loaders still flowing
    } else if (pack_status === "producing" && pall_status === "producing") {
        flag_decrease_robot = true;
        flag_decrease_load  = true;
        new_robot_speed = Math.max(1, rob_speed  - 1);
        new_load_speed  = Math.max(1, pack_speed - 1);
        suggestion =
            "Robot blocked downstream, both loaders still flowing — queues will fill soon. " +
            "Decrease robot speed to " + new_robot_speed +
            " and package loader speed to " + new_load_speed +
            ". Put forklifts in eco mode to slow product arrival.";
        pass = false;
    }

// ─────────────────────────────────────────────
// ROBOT = PRODUCING
// Fine-tune speeds to drain backed-up queues.
// ─────────────────────────────────────────────
} else if (rob_status === "producing") {

    // Case 11 — Both loader queues full
    if (pack_status === "blocked" && pall_status === "blocked") {
        flag_increase_robot = true;
        new_robot_speed = pack_speed;
        suggestion =
            "Both loader queues are full. Increase speed to " + new_robot_speed +
            " to consume input faster. " +
            "Put forklifts in eco mode to slow product arrival while queues drain.";
        pass = false;

    } else if (pack_status === "blocked" && pall_status === "producing") {

        if (pall_speed >= pack_speed) {
            // Case 12 — Pallet speed sufficient, drain package queue by speeding robot
            flag_increase_robot = true;
            new_robot_speed = pack_speed;
            suggestion =
                "Package queue is full and pallet loader speed (" + pall_speed +
                ") >= package loader speed (" + pack_speed +
                "). Increase speed to " + new_robot_speed +
                " to drain the package queue.";
            pass = false;

        } else {
            // Case 13 — Pallet is the bottleneck; slow package loader to match
            flag_decrease_load = true;
            new_load_speed = pall_speed;
            suggestion =
                "Package queue is full but pallet loader (" + pall_speed +
                ") is slower than package loader (" + pack_speed +
                "). Decrease speed to " + new_load_speed +
                " to match pallet product throughput.";
            pass = false;
        }

    } else if (pall_status === "blocked" && pack_status === "producing") {

        if (rob_speed < pack_speed) {
            // Case 14 — Robot can speed up to drain pallet (product) queue
            flag_increase_robot = true;
            new_robot_speed = Math.min(pack_speed, pall_speed);
            suggestion =
                "Pallet queue is full and robot speed (" + rob_speed +
                ") < package loader speed (" + pack_speed +
                "). Increase speed to " + new_robot_speed +
                " to drain the product queue.";
            pass = false;

        } else {
            // Case 15 — Robot at or above pack speed; pallet still backing up
            flag_increase_robot = true;
            flag_increase_load  = true;
            new_robot_speed = pall_speed;
            new_load_speed  = pall_speed;
            suggestion =
                "Pallet queue is full and robot speed (" + rob_speed +
                ") >= package loader speed (" + pack_speed +
                "). Increase speed to " + new_robot_speed +
                ". Put forklifts in eco mode to slow product arrival if needed.";
            pass = false;
        }

    // Case 16 — Nominal
    } else if (pack_status === "producing" && pall_status === "producing") {
        pass = true;
    }
}

