const payload = msg.payload || {};

const PRIORITY_ORDER = ["Production QC", "Batch QC", "Block Analysis"];

const MACHINES = [
    { key: "robot",          flagSuffix: "robot",  controllable: true  },
    { key: "package_loader", flagSuffix: "load", controllable: true  },
    { key: "pallet_loader",  flagSuffix: "pallet", controllable: false },
];

const decisions = {};

let anyFailed = false;

for (const sectionName of PRIORITY_ORDER) {
    if (!(sectionName in payload)) continue;

    const section = payload[sectionName] || {};

    if (section.pass === true) continue;

    anyFailed = true;

    const suggestion = section.suggestion || "";

    for (const machine of MACHINES) {
        if (decisions[machine.key]) continue;

        const flagIncrease = section["flag_increase_" + machine.flagSuffix] === true;
        const flagDecrease = section["flag_decrease_" + machine.flagSuffix] === true;
        const new_speed = section["new_" + machine.flagSuffix + "_speed"] || null;

        if (flagIncrease && machine.controllable) {
            decisions[machine.key] = { mode: "increase", reason: suggestion, speed:new_speed };
        } else if (flagDecrease && machine.controllable) {
            decisions[machine.key] = { mode: "decrease", reason: suggestion, speed:new_speed };
        } else if (suggestion) {
            decisions[machine.key] = { mode: "ok", reason: suggestion };
        }
    }

    const hasActionable = MACHINES.some(
        m => m.controllable &&
             decisions[m.key] &&
             decisions[m.key].mode !== "ok"
    );
    if (hasActionable) break;

}

if (!anyFailed) {
    msg.payload = { status: "ok" };
    return msg;
}

const output = { status: "not ok" };

for (const machine of MACHINES) {
    if (decisions[machine.key]) {
        output[machine.key] = decisions[machine.key];
    }
}

msg.payload = output;
return msg;

