function convertToSuggestions(payload) {
  if (payload.status === "ok") {
    return "Line ok";
  }

  const suggestions = [];
  const skip = new Set(["status"]);
  var last_reason = null

  for (const [machine, data] of Object.entries(payload)) {
    if (skip.has(machine)) continue;
    if (!data || typeof data !== "object") continue;

    const { mode, reason } = data;
    last_reason= reason

    if (mode === "ok") continue;

    if (mode === "increase" || mode === "decrease") {
      const label = machine
        .replace(/_/g, " ")
        .replace(/\b\w/g, c => c.toUpperCase());
      suggestions.push(`[${label}]: ${reason}\n`);
    }
  }

  return suggestions.length > 0 ? suggestions.join("\n") : last_reason;
}


msg.payload = {suggestion: convertToSuggestions(suggestion)}
return msg

