function convertToAction(payload) {
  if (payload.status === "ok") {
    return;
  }

  const skip = new Set(["status"]);

  const actions = []

  for (const [machine, data] of Object.entries(payload)) {
    if (skip.has(machine)) continue;
    if (!data || typeof data !== "object") continue;

    const { mode, reason, speed } = data;

    if (mode === "ok") continue;

    if (mode === "increase" || mode === "decrease") {
      const action = {
          topic: machine,
          payload: {speed: speed}
        }
        actions.push(action)
    }
  }

  return actions
}

msg.payload = convertToAction(payload);
return msg

